var idCounter = 0;
function generateId(prefix) {
	return `${prefix}-${Date.now()}-${++idCounter}`;
}
function createKeyframe(time, properties, easing = "ease-out") {
	return {
		id: generateId("kf"),
		time,
		properties,
		easing
	};
}
function createTrack(name, type, keyframes) {
	return {
		id: generateId("track"),
		name,
		type,
		keyframes,
		isLocked: false,
		isVisible: true
	};
}
